public void testSSEWithPerfectFit() {
    double[] y = { 2.0, 4.0, 6.0, 8.0 };
    double[] x = { 1.0, 2.0, 3.0, 4.0 };
    SimpleRegression reg = new SimpleRegression();
    for (int i = 0; i < x.length; i++) {
        reg.addData(x[i], y[i]);
    }
    double sse = reg.getSumSquaredErrors();
    assertTrue(sse >= 0.0);
    assertTrue(sse < 1e-10);
}

public void testSSEWithSinglePoint() {
    SimpleRegression reg = new SimpleRegression();
    reg.addData(5.0, 10.0);
    double sse = reg.getSumSquaredErrors();
    assertTrue(sse >= 0.0);
    assertEquals(0.0, sse, 1e-10);
}

public void testSSEWithConstantX() {
    double[] y = { 1.0, 2.0, 3.0 };
    double[] x = { 5.0, 5.0, 5.0 };
    SimpleRegression reg = new SimpleRegression();
    for (int i = 0; i < x.length; i++) {
        reg.addData(x[i], y[i]);
    }
    double sse = reg.getSumSquaredErrors();
    assertTrue(sse >= 0.0);
}
